export type PictureFileProps = FileProps & {
  /**
   * 自定义文件预览行为，需要返回文件 url
   */
  previewFile?: PreviewFileHandler;
};
export function PictureFile(props: PictureFileProps) {
  const { style, previewFile = previewImage } = props;
  const locale = useLocaleReceiver('upload');
  const [isOverFileItem, setIsOverFileItem] = React.useState(false);
  const [isOverOperationItems, setIsOverOperationItems] = React.useState(false);

  const fileCtxValue = useFile(props);
  const {
    file,
    disabled,
    onRemove,
    rootPrefixCls,
    progressProps,
    classNames,
    downloadNode,
    retryNode,
    previewNode,
    showErrorIcon,
  } = fileCtxValue;

  warning(
    !(['downloading', 'downloadFailed', 'downloaded'] as UploadFileStatus[]).includes(file.status),
    devWarning('Upload', `file.status=${file.status} does not support for PictureFile.`),
  );

  const forceUpdate = useForceUpdate();

  // 生成缩略图
  React.useEffect(() => {
    if (
      typeof document === 'undefined' ||
      typeof window === 'undefined' ||
      !(window as any).FileReader ||
      !(window as any).File ||
      !file.originFileObj ||
      !(file.originFileObj instanceof File || (file.originFileObj as Blob) instanceof Blob) ||
      file.thumbUrl !== undefined
    ) {
      return;
    }
    file.thumbUrl = '';
    if (previewFile) {
      previewFile(file.originFileObj as File).then((previewDataUrl: string) => {
        // Need append '' to avoid dead loop
        file.thumbUrl = previewDataUrl || '';
        forceUpdate();
      });
    }
  }, [previewFile, forceUpdate, file]);

  const imgUrl = file.thumbUrl || file.url;
  const visible = isOverFileItem && !isOverOperationItems && showErrorIcon && file.status === 'error';

  return (
    <FileContextProvider value={fileCtxValue}>
      <Tooltip title={file.failedReason || locale.failed} visible={visible}>
        <div
          className={clsx(classNames, `${rootPrefixCls}--picture`)}
          style={style}
          onMouseEnter={() => setIsOverFileItem(true)}
          onMouseLeave={() => setIsOverFileItem(false)}
        >
          {imgUrl && <img src={imgUrl} />}
          <UploadProgress file={file} progressProps={progressProps} prefixCls={rootPrefixCls} />

          <div className={`${rootPrefixCls}--picture-operations`}>
            <div
              className={stylex(
                stylex.create({
                  display: 'contents',
                }),
              )}
              onMouseEnter={() => setIsOverOperationItems(true)}
              onMouseLeave={() => setIsOverOperationItems(false)}
            >
              {retryNode}
              {previewNode}
              {downloadNode}
            </div>
          </div>
          <div className={`${rootPrefixCls}--picture-mask`} />

          {!disabled && (
            <div className={`${rootPrefixCls}--picture-close`} onClick={() => onRemove?.()}>
              {pictureCloseSvg}
            </div>
          )}
        </div>
      </Tooltip>
    </FileContextProvider>
  );
}
